// Package anypb is wiresmith's drop-in replacement for the well-known
// google.protobuf.Any. The generated struct (any.pb.go) carries wiresmith's
// wire methods (Size/Marshal/Unmarshal/Equal/Compare) so that messages
// referencing google.protobuf.Any can be generated by wiresmith — the
// official google.golang.org/protobuf/types/known/anypb.Any lacks those
// methods.
//
// This file supplies the rest of the Any contract by hand:
//   - ProtoReflect, which delegates to the official Any descriptor rather than
//     registering a second one (the official runtime already registers
//     google/protobuf/any.proto and the google.protobuf.Any message; a second
//     registration of the same file/message panics at init), so the type is a
//     valid proto.Message — required wherever an imported message lands in a
//     consumer's protoimpl.TypeBuilder goTypes.
//   - The typed helpers (MarshalFrom/UnmarshalTo/UnmarshalNew/MessageName/
//     TypeName) for parity with the official and gogo Any APIs.
package anypb

import (
	"errors"
	"fmt"
	"strings"

	"google.golang.org/protobuf/proto"
	"google.golang.org/protobuf/reflect/protoreflect"
	"google.golang.org/protobuf/reflect/protoregistry"
	officialanypb "google.golang.org/protobuf/types/known/anypb"
)

// urlPrefix is the conventional type-URL prefix MarshalFrom writes; it matches
// the official anypb and gogoproto behaviour.
const urlPrefix = "type.googleapis.com/"

// ProtoReflect makes *Any a proto.Message by delegating to the official Any's
// reflection, which is backed by the descriptor the official runtime already
// registered. wiresmith deliberately does not register this package's own
// descriptor (that would conflict), so the returned message is a detached view
// over a copy of the fields — sufficient for descriptor/type resolution (e.g.
// a consumer's reflect init) but not a write-through handle.
func (x *Any) ProtoReflect() protoreflect.Message {
	return (&officialanypb.Any{TypeUrl: x.GetTypeUrl(), Value: x.GetValue()}).ProtoReflect()
}

// MessageName returns the fully-qualified name of the message packed in x,
// parsed from the type URL (the substring after the last '/'). It returns the
// empty name when the URL is empty or the parsed name is not a valid proto
// full name — same contract as the official anypb.Any.MessageName.
func (x *Any) MessageName() protoreflect.FullName {
	url := x.GetTypeUrl()
	name := protoreflect.FullName(url)
	if i := strings.LastIndexByte(url, '/'); i >= 0 {
		name = name[i+len("/"):]
	}
	if !name.IsValid() {
		return ""
	}
	return name
}

// TypeName returns MessageName as a string — the bead's requested spelling and
// the gogoproto-style accessor.
func (x *Any) TypeName() string {
	return string(x.MessageName())
}

// MessageIs reports whether x holds a message of m's type.
func (x *Any) MessageIs(m proto.Message) bool {
	if m == nil {
		return false
	}
	return x.MessageName() == m.ProtoReflect().Descriptor().FullName()
}

// MarshalFrom serializes src into x, setting the type URL from src's full name.
func (x *Any) MarshalFrom(src proto.Message) error {
	if src == nil {
		return errors.New("anypb: invalid nil source message")
	}
	b, err := proto.Marshal(src)
	if err != nil {
		return err
	}
	x.TypeUrl = urlPrefix + string(src.ProtoReflect().Descriptor().FullName())
	x.Value = b
	return nil
}

// UnmarshalTo deserializes x's value into dst, requiring dst's type to match
// x's packed message type.
func (x *Any) UnmarshalTo(dst proto.Message) error {
	if dst == nil {
		return errors.New("anypb: invalid nil destination message")
	}
	if !x.MessageIs(dst) {
		return fmt.Errorf("anypb: mismatched message type: got %q, want %q",
			dst.ProtoReflect().Descriptor().FullName(), x.MessageName())
	}
	return proto.Unmarshal(x.GetValue(), dst)
}

// UnmarshalNew resolves x's packed message type from the global type registry,
// allocates a new instance, and deserializes x's value into it.
func (x *Any) UnmarshalNew() (proto.Message, error) {
	if x.GetTypeUrl() == "" {
		return nil, errors.New("anypb: invalid empty type URL")
	}
	mt, err := protoregistry.GlobalTypes.FindMessageByURL(x.GetTypeUrl())
	if err != nil {
		return nil, fmt.Errorf("anypb: could not resolve %q: %w", x.GetTypeUrl(), err)
	}
	dst := mt.New().Interface()
	return dst, proto.Unmarshal(x.GetValue(), dst)
}

// New packs src into a fresh *Any, mirroring the official anypb.New.
func New(src proto.Message) (*Any, error) {
	dst := &Any{}
	if err := dst.MarshalFrom(src); err != nil {
		return nil, err
	}
	return dst, nil
}
